#include "interface.h"

namespace {
static inline uint64_t fnv_mix(uint64_t h, uint64_t v) {
  // FNV-1a step
  h ^= v;
  h *= 1099511628211ULL;
  return h;
}
}  // namespace

uint64_t ragged_pack_checksum(const std::vector<uint32_t>& padded_tokens, const std::vector<int>& lengths, int batch, int max_len, int iters) {
  uint64_t hash = 0;  // Preserve baseline behavior when iters == 0
  const uint32_t* data = padded_tokens.data();
  const int* lens = lengths.data();

  for (int iter = 0; iter < iters; ++iter) {
    uint64_t h = 1469598103934665603ULL;  // FNV offset basis
    for (int b = 0; b < batch; ++b) {
      int len = lens[static_cast<std::size_t>(b)];
      const uint32_t* row = data + static_cast<std::size_t>(b) * static_cast<std::size_t>(max_len);
      for (int i = 0; i < len; ++i) {
        h = fnv_mix(h, static_cast<uint64_t>(row[static_cast<std::size_t>(i)]));
        h = fnv_mix(h, static_cast<uint64_t>(static_cast<uint32_t>(i)));
      }
    }
    hash = h;  // Same as baseline: overwrite each iter and return last
  }
  return hash;
}
